solution_code:
#include <iostream>

int main()
{
    int a = 0;
    int b = 0;
    std::cin >> a >> b;

    std::cout << "a + b = " << a + b << '\n';
    std::cout << "a - b = " << a - b << '\n';
    std::cout << "a * b = " << a * b << '\n';
    std::cout << "a / b = " << a / b << '\n';
    std::cout << "a % b = " << a % b << '\n';

    return 0;
}

