solution_code:
#include <iostream>

int main()
{
    int a = 0;
    int b = 0;
    std::cin >> a >> b;

    int quotient = a / b;
    int remainder = a % b;
    int check = a - quotient * b;

    std::cout << "quotient: " << quotient << '\n';
    std::cout << "remainder: " << remainder << '\n';
    std::cout << "check: " << check << '\n';

    return 0;
}
